/bin/bash -lc "python - <<'PY'
from openpyxl import load_workbook
files = [
'desktop/2-financial-analysis-tables/4-financial-table-income-expense-dashboard.xlsx',
'desktop/2-financial-analysis-tables/5-financial-table-income-expense-profit-statement_visual-charts_.xlsx',
'desktop/2-financial-analysis-tables/6-financial-table-income-and-expense-data-visual-charts.xlsx'
]
for f in files:
    print('\\nFILE:', f)
    wb = load_workbook(f, data_only=True)
    for ws in wb.worksheets:
        print('Sheet:', ws.title, 'rows', ws.max_row, 'cols', ws.max_column)
        nonempty=[]
        for row in ws.iter_rows():
            vals=[c.value for c in row]
            if any(v is not None and v"'!='"'' for v in vals):
                # compress row to index:value pairs for first 20 nonempty cells
                items=[]
                for i,v in enumerate(vals, start=1):
                    if v is not None and v"'!='"'':
                        items.append(f'{i}:{v}')
                    if len(items)>=12:
                        break
                nonempty.append(items)
            if len(nonempty)>=15:
                break
        for items in nonempty:
            print(' ', items)
        print('---')
PY"

